"""
Enhanced System Librarian
Maintains transcript logs, generates documentation, and manages system knowledge
Provides complete system understanding from any module's perspective
"""

import json
import logging
import re
import uuid
from dataclasses import dataclass, field
from datetime import datetime, timezone
from enum import Enum
from typing import Any, Dict, List, Optional

logger = logging.getLogger("system_librarian")


class DocumentType(Enum):
    """Types of documents generated by librarian"""
    TRANSCRIPT = "transcript"
    TECHNICAL_DOC = "technical_documentation"
    API_REFERENCE = "api_reference"
    USER_MANUAL = "user_manual"
    MODULE_GUIDE = "module_guide"
    REPORT = "report"
    AUDIT_LOG = "audit_log"


@dataclass
class TranscriptEntry:
    """Single entry in system transcript"""
    entry_id: str
    timestamp: str
    module: str
    action: str
    details: Dict[str, Any]
    actor: str  # user or bot_id
    success: bool
    duration_ms: Optional[int] = None

    def to_dict(self) -> Dict:
        return {
            "entry_id": self.entry_id,
            "timestamp": self.timestamp,
            "module": self.module,
            "action": self.action,
            "details": self.details,
            "actor": self.actor,
            "success": self.success,
            "duration_ms": self.duration_ms
        }


@dataclass
class SystemKnowledge:
    """Knowledge entry about system aspect"""
    knowledge_id: str
    category: str
    topic: str
    description: str
    related_modules: List[str]
    related_functions: List[str]
    references: List[str]
    created_at: str
    updated_at: str = field(default_factory=lambda: datetime.now(timezone.utc).isoformat())

    def to_dict(self) -> Dict:
        return {
            "knowledge_id": self.knowledge_id,
            "category": self.category,
            "topic": self.topic,
            "description": self.description,
            "related_modules": self.related_modules,
            "related_functions": self.related_functions,
            "references": self.references,
            "created_at": self.created_at,
            "updated_at": self.updated_at
        }


@dataclass
class GeneratedDocument:
    """Document generated by librarian"""
    doc_id: str
    doc_type: DocumentType
    title: str
    content: str
    format: str  # markdown, html, json
    metadata: Dict[str, Any]
    created_at: str
    version: str = "1.0"

    def to_dict(self) -> Dict:
        return {
            "doc_id": self.doc_id,
            "doc_type": self.doc_type.value,
            "title": self.title,
            "content": self.content,
            "format": self.format,
            "metadata": self.metadata,
            "created_at": self.created_at,
            "version": self.version
        }


@dataclass
class GeneratedCommand:
    """A command generated by the Librarian from a natural-language description.

    Attributes:
        command: Canonical slash command (e.g. ``/data pipeline run``).
        chat_command: Chat alias form (e.g. ``!murphy data pipeline run``).
        module_name: Source module that provides this command.
        category: Command category string (e.g. ``"data"``).
        description: Human-readable description of what the command does.
        setpoints: Extracted parameter values from the user's description
                   (e.g. ``{"pipeline_id": "sales_etl", "replicas": "3"}``).
        confidence: Match confidence in [0.0, 1.0].
        explanation: Why this command was selected.
        alternatives: List of other command dicts considered.
    """

    command: str
    chat_command: str
    module_name: str
    category: str
    description: str
    setpoints: Dict[str, Any]
    confidence: float
    explanation: str
    alternatives: List[Dict[str, Any]] = field(default_factory=list)

    def to_dict(self) -> Dict[str, Any]:
        return {
            "command": self.command,
            "chat_command": self.chat_command,
            "module_name": self.module_name,
            "category": self.category,
            "description": self.description,
            "setpoints": self.setpoints,
            "confidence": round(self.confidence, 4),
            "explanation": self.explanation,
            "alternatives": self.alternatives,
        }


class SystemLibrarian:
    """
    Enhanced system librarian
    Maintains complete transcript logs and generates documentation
    Provides system understanding from any module's perspective
    """

    def __init__(self):
        self.transcripts: List[TranscriptEntry] = []
        self.knowledge_base: Dict[str, SystemKnowledge] = {}
        self.documents: Dict[str, GeneratedDocument] = {}

        self.entry_count = 0
        self.knowledge_count = 0
        self.doc_count = 0

        # Initialize system knowledge
        self._initialize_system_knowledge()

        # Module function mappings
        self.module_functions = self._load_module_functions()

        # Module capabilities
        self.module_capabilities = self._load_module_capabilities()

        # Auto-bootstrap the universal command registry so every slash command,
        # chat command, and NL alias is immediately available to find_capabilities()
        # and generate_command() without any external call.
        try:
            from murphy_terminal.command_registry import build_registry  # type: ignore[import]
            self.load_command_registry(build_registry())
        except Exception as exc:
            logger.debug(
                "SystemLibrarian: command registry auto-bootstrap skipped (%s: %s)",
                type(exc).__name__,
                exc,
            )

