    def log_transcript(
        self,
        module: str,
        action: str,
        details: Dict[str, Any],
        actor: str,
        success: bool,
        duration_ms: Optional[int] = None
    ):
        """
        Log an entry to system transcript

        Args:
            module: Module performing action
            action: Action performed
            details: Action details
            actor: Actor (user or bot_id)
            success: Whether action succeeded
            duration_ms: Duration of action in milliseconds
        """
        self.entry_count += 1
        entry = TranscriptEntry(
            entry_id=f"entry_{self.entry_count}",
            timestamp=datetime.now(timezone.utc).isoformat(),
            module=module,
            action=action,
            details=details,
            actor=actor,
            success=success,
            duration_ms=duration_ms
        )
        self.transcripts.append(entry)

    def get_transcripts(
        self,
        module: Optional[str] = None,
        actor: Optional[str] = None,
        limit: Optional[int] = None
    ) -> List[TranscriptEntry]:
        """
        Get transcripts filtered by criteria

        Args:
            module: Filter by module
            actor: Filter by actor
            limit: Limit number of entries

        Returns:
            List of transcript entries
        """
        filtered = self.transcripts

        if module:
            filtered = [t for t in filtered if t.module == module]

        if actor:
            filtered = [t for t in filtered if t.actor == actor]

        if limit:
            filtered = filtered[-limit:]

        return filtered

    def get_module_documentation(self, module_name: str) -> Dict[str, Any]:
        """
        Get complete documentation for a module

        Args:
            module_name: Name of module

        Returns:
            Module documentation
        """
        # Get module functions
        functions = self.module_functions.get(module_name, {})

        # Get module capabilities
        capabilities = self.module_capabilities.get(module_name, [])

        # Get related knowledge
        related_knowledge = [
            k.to_dict() for k in self.knowledge_base.values()
            if module_name in k.related_modules
        ]

        # Get module transcripts
        module_transcripts = self.get_transcripts(module=module_name, limit=50)

        return {
            "module_name": module_name,
            "functions": functions,
            "capabilities": capabilities,
            "related_knowledge": related_knowledge,
            "recent_activity": [t.to_dict() for t in module_transcripts],
            "coupled": True,
            "help_visible": True
        }

    def get_function_documentation(self, module_name: str, function_name: str) -> Optional[Dict]:
        """
        Get documentation for a specific function

        Args:
            module_name: Name of module
            function_name: Name of function

        Returns:
            Function documentation
        """
        module_functions = self.module_functions.get(module_name, {})
        return module_functions.get(function_name)

    def generate_module_guide(self, module_name: str) -> GeneratedDocument:
        """
        Generate comprehensive module guide

        Args:
            module_name: Name of module

        Returns:
            GeneratedDocument object
        """
        doc = self.get_module_documentation(module_name)

        # Build markdown content
        content = f"# {module_name.title()} Module Guide\n\n"

        content += "## Overview\n\n"
        content += f"The {module_name} module provides the following capabilities:\n\n"
        for capability in doc["capabilities"]:
            content += f"- {capability}\n"

        content += "\n## Functions\n\n"
        for func_name, func_data in doc["functions"].items():
            content += f"### {func_name}\n\n"
            content += f"**Description**: {func_data['description']}\n\n"
            content += f"**Parameters**: {', '.join(func_data['parameters'])}\n\n"
            content += f"**Returns**: {func_data['returns']}\n\n"

        content += "\n## Recent Activity\n\n"
        for transcript in doc["recent_activity"][-10:]:
            content += f"- {transcript['timestamp']}: {transcript['action']} ({'✓' if transcript['success'] else '✗'})\n"

        self.doc_count += 1
        document = GeneratedDocument(
            doc_id=f"doc_{self.doc_count}",
            doc_type=DocumentType.MODULE_GUIDE,
            title=f"{module_name.title()} Module Guide",
            content=content,
            format="markdown",
            metadata={
                "module": module_name,
                "version": "1.0",
                "generated_at": datetime.now(timezone.utc).isoformat()
            },
            created_at=datetime.now(timezone.utc).isoformat()
        )

        self.documents[document.doc_id] = document
        return document

    def generate_complete_transcript(self) -> GeneratedDocument:
        """Generate complete system transcript document"""
        content = "# Complete System Transcript\n\n"
        content += f"Generated at: {datetime.now(timezone.utc).isoformat()}\n\n"
        content += f"Total entries: {len(self.transcripts)}\n\n"

        # Group by module
        by_module = {}
        for entry in self.transcripts:
            if entry.module not in by_module:
                by_module[entry.module] = []
            by_module[entry.module].append(entry)

        for module, entries in by_module.items():
            content += f"\n## {module}\n\n"
            for entry in entries[-20:]:  # Last 20 entries per module
                status = "✓" if entry.success else "✗"
                content += f"- [{entry.timestamp}] {entry.action} by {entry.actor} {status}\n"
                if entry.details:
                    content += f"  Details: {json.dumps(entry.details, indent=2)}\n"

        self.doc_count += 1
        document = GeneratedDocument(
            doc_id=f"doc_{self.doc_count}",
            doc_type=DocumentType.TRANSCRIPT,
            title="Complete System Transcript",
            content=content,
            format="markdown",
            metadata={
                "total_entries": len(self.transcripts),
                "modules": list(by_module.keys()),
                "generated_at": datetime.now(timezone.utc).isoformat()
            },
            created_at=datetime.now(timezone.utc).isoformat()
        )

        self.documents[document.doc_id] = document
        return document

    def search_knowledge(self, query: str) -> List[SystemKnowledge]:
        """
        Search knowledge base

        Args:
            query: Search query

        Returns:
            List of matching knowledge entries
        """
        query_lower = query.lower()
        results = []

        for knowledge in self.knowledge_base.values():
            # Search in topic, description, category
            if (query_lower in knowledge.topic.lower() or
                query_lower in knowledge.description.lower() or
                query_lower in knowledge.category.lower()):
                results.append(knowledge)

        return results

    def get_system_overview(self) -> Dict[str, Any]:
        """Get complete system overview from librarian perspective"""
        return {
            "total_modules": len(self.module_functions),
            "total_functions": sum(len(funcs) for funcs in self.module_functions.values()),
            "total_transcripts": len(self.transcripts),
            "total_knowledge": len(self.knowledge_base),
            "total_documents": len(self.documents),
            "modules": list(self.module_functions.keys()),
            "module_summary": {
                module: {
                    "functions": len(funcs),
                    "capabilities": len(caps)
                }
                for module, funcs, caps in zip(
                    self.module_functions.keys(),
                    self.module_functions.values(),
                    self.module_capabilities.values()
                )
            }
        }

    def get_documentation(self, topic: str = "capabilities") -> Dict[str, Any]:
        """Convenience method: get documentation by topic"""
        results = self.search_knowledge(topic)
        if results:
            return {"topic": topic, "entries": [r.__dict__ if hasattr(r, '__dict__') else str(r) for r in results]}
        return self.get_system_overview()

    def get_help(self) -> Dict[str, Any]:
        """Convenience method: get help overview"""
        return self.get_system_overview()

    def answer_question(self, question: str) -> Dict[str, Any]:
        """Convenience method: answer a question using the knowledge base"""
        results = self.search_knowledge(question)
        entries = [r.__dict__ if hasattr(r, '__dict__') else str(r) for r in results]
        return {"question": question, "answer": entries if entries else ["No specific answer found."], "results": entries}

    def troubleshoot(self, issue: str) -> Dict[str, Any]:
        """Convenience method: troubleshoot an issue"""
        results = self.search_knowledge(issue)
        entries = [r.__dict__ if hasattr(r, '__dict__') else str(r) for r in results]
        return {"issue": issue, "suggestions": entries if entries else ["Check system logs for more details."]}

    def add_knowledge_entry(self, entry: Dict[str, Any]) -> "SystemKnowledge":
        """Add a single knowledge entry to the knowledge base.

        Args:
            entry: Dict with keys ``category``, ``topic``, ``description``,
                   ``related_modules``, ``related_functions``, ``references``.

        Returns:
            The newly created SystemKnowledge object.
        """
        self.knowledge_count += 1
        knowledge = SystemKnowledge(
            knowledge_id=f"know_{self.knowledge_count}",
            category=entry.get("category", "general"),
            topic=entry.get("topic", ""),
            description=entry.get("description", ""),
            related_modules=entry.get("related_modules", []),
            related_functions=entry.get("related_functions", []),
            references=entry.get("references", []),
            created_at=datetime.now(timezone.utc).isoformat(),
        )
        self.knowledge_base[knowledge.knowledge_id] = knowledge
        return knowledge

    def register_schema_knowledge(self, registry: Any) -> int:
        """Index all registered schemas from a SchemaRegistry into the knowledge base.

        Args:
            registry: A SchemaRegistry instance whose ``schemas`` dict will be
                      indexed.

        Returns:
            Number of knowledge entries added.
        """
        count = 0
        for key, schema in registry.schemas.items():
            self.add_knowledge_entry({
                "category": "schema_contract",
                "topic": f"Schema: {schema.artifact_name} ({schema.direction})",
                "description": f"I/O schema for {schema.artifact_name}",
                "related_modules": [key.split(":")[0]],  # bot_name
                "related_functions": [],
                "references": [f"schema:{key}"],
            })
            count += 1
        return count

    # ------------------------------------------------------------------
    # Librarian-driven routing support
    # ------------------------------------------------------------------

    def find_capabilities(
        self,
        task: Dict[str, Any],
        top_n: int = 5,
        module_registry: Optional[Any] = None,
    ) -> List[Any]:
        """Return a ranked list of :class:`~task_router.CapabilityMatch` objects.

        Two-phase discovery:

        **Phase 1 — Pre-filter**: capabilities incompatible with the task domain
        are flagged but still returned (with ``filtered=True``) so operators can
        see what was excluded and why.

        **Phase 2 — Score and rank**: surviving capabilities are scored using
        keyword overlap between the task text and the capability description.
        The top *top_n* matches are returned, sorted by descending score.

        Args:
            task: Task dict, e.g. ``{"task": "generate invoice for Acme $5000"}``.
            top_n: Maximum number of unfiltered matches to return.
            module_registry: Optional :class:`~module_registry.ModuleRegistry`
                instance.  When supplied its live capability map is merged with
                the built-in ``module_capabilities`` map for broader coverage.

        Returns:
            List of ``CapabilityMatch`` instances (unfiltered ones first, sorted
            by descending score; filtered ones appended at the end).
        """
        # Import here to avoid circular imports at module load time
        try:
            from task_router import CapabilityMatch  # type: ignore[import]
        except ImportError:
            # Fallback: define a minimal CapabilityMatch locally if task_router
            # is not yet on sys.path (e.g. during isolated unit tests)
            from dataclasses import dataclass
            from dataclasses import field as _field

            @dataclass  # type: ignore[no-redef]
            class CapabilityMatch:  # type: ignore[no-redef]
                capability_id: str
                module_path: str
                score: float
                match_reasons: List[str] = _field(default_factory=list)
                cost_estimate: str = "medium"
                determinism: str = "deterministic"
                gate_compatibility: Dict[str, str] = _field(default_factory=dict)
                filtered: bool = False
                filter_reason: Optional[str] = None

        task_text = str(task.get("task", task.get("description", ""))).lower()
        task_words = set(task_text.split())

        # Build the combined capability map
        combined: Dict[str, List[str]] = {}
        # 1. Built-in per-module capability descriptions
        for module_name, cap_list in self.module_capabilities.items():
            for cap in cap_list:
                cap_key = cap.lower().replace(" ", "_")
                combined.setdefault(cap_key, []).append(module_name)

        # 2. Live ModuleRegistry capabilities (tag-style)
        if module_registry is not None:
            try:
                live_caps = module_registry.get_capabilities()
                if isinstance(live_caps, dict):
                    for cap_tag, modules in live_caps.items():
                        mods = modules if isinstance(modules, list) else [modules]
                        combined.setdefault(cap_tag.lower(), []).extend(mods)
            except Exception as exc:
                logger.debug("SystemLibrarian.find_capabilities: registry error: %s", exc)

        matches: List[Any] = []
        seen_caps: set = set()

        for cap_key, modules in combined.items():
            if cap_key in seen_caps:
                continue
            seen_caps.add(cap_key)

            cap_words = set(cap_key.replace("_", " ").split())
            overlap = task_words & cap_words
            if not task_words:
                score = 0.0
            else:
                score = len(overlap) / max(len(task_words), len(cap_words))

            module_name = modules[0] if modules else "unknown"
            match = CapabilityMatch(
                capability_id=cap_key,
                module_path=f"src.{module_name}",
                score=round(score, 4),
                match_reasons=[f"keyword overlap: {sorted(overlap)}"] if overlap else ["no direct overlap"],
                cost_estimate="medium",
                determinism="deterministic",
                gate_compatibility={},
                filtered=False,
                filter_reason=None,
            )
            matches.append(match)

        # Sort by descending score
        matches.sort(key=lambda m: m.score, reverse=True)

        # Return top_n unfiltered + all filtered ones
        unfiltered = [m for m in matches if not m.filtered][:top_n]
        filtered = [m for m in matches if m.filtered]
        return unfiltered + filtered

    # ------------------------------------------------------------------
    # CommandRegistry integration
    # ------------------------------------------------------------------

    def load_command_registry(self, registry: Any) -> int:
        """Ingest a :class:`~murphy_terminal.command_registry.CommandRegistry` into
        the Librarian's capability and knowledge maps.

        Every ``CommandDefinition`` in *registry* is registered as:

        * A capability string in ``module_capabilities[module_name]``
        * A function entry in ``module_functions[module_name]``
        * A knowledge entry (category = command category, topic = description)

        This makes every slash command, chat command, and natural-language alias
        discoverable by :meth:`find_capabilities` and :meth:`generate_command`
        without any additional wiring.

        Args:
            registry: A fully-bootstrapped ``CommandRegistry`` instance.

        Returns:
            Number of command definitions loaded.
        """
        count = 0
        try:
            commands = registry.all_commands()
        except Exception as exc:
            logger.warning("load_command_registry: could not enumerate commands: %s", exc)
            return 0

        for cmd in commands:
            module = cmd.module_name
            # ---- capability strings ----
            cap_list = self.module_capabilities.setdefault(module, [])
            cap_entry = cmd.description
            if cap_entry not in cap_list:
                cap_list.append(cap_entry)
            # Add NL aliases so keyword matching picks them up too
            for alias in getattr(cmd, "nl_aliases", []):
                if alias not in cap_list:
                    cap_list.append(alias)

            # ---- function entry ----
            func_map = self.module_functions.setdefault(module, {})
            func_map[cmd.slash_command] = {
                "description": cmd.description,
                "parameters": getattr(cmd, "subcommands", []),
                "usage": getattr(cmd, "usage", cmd.slash_command),
                "chat_command": cmd.chat_command,
                "nl_aliases": getattr(cmd, "nl_aliases", []),
                "category": cmd.category if isinstance(cmd.category, str) else cmd.category.value,
                "min_role": getattr(cmd, "min_role", "viewer"),
                "requires_args": getattr(cmd, "requires_args", False),
                "examples": getattr(cmd, "examples", []),
                "returns": "CommandResult",
                "help_visible": True,
                "coupled": True,
            }

            # ---- knowledge entry ----
            self.add_knowledge_entry({
                "category": f"command_{cmd.category if isinstance(cmd.category, str) else cmd.category.value}",
                "topic": f"Command: {cmd.slash_command}",
                "description": (
                    f"{cmd.description}. "
                    f"Usage: {getattr(cmd, 'usage', cmd.slash_command)}. "
                    f"Chat: {cmd.chat_command}."
                ),
                "related_modules": [module],
                "related_functions": [cmd.slash_command],
                "references": [f"command:{cmd.slash_command}"],
            })
            count += 1

        logger.info("load_command_registry: loaded %d commands into Librarian", count)
        return count

    def generate_command(
        self,
        description: str,
        context: Optional[Dict[str, Any]] = None,
        top_n: int = 5,
    ) -> Optional[GeneratedCommand]:
        """Translate a plain-English description into the best-matching Murphy command
        with extracted setpoints.

        The method uses a three-pass strategy:

        1. **NL-alias exact match** — looks up ``description`` against every
           command's ``nl_aliases`` via the loaded :class:`CommandRegistry`.
        2. **Keyword overlap scoring** — scores every command whose description
           words overlap with *description* words, using TF-inspired weighting.
        3. **Generic fallback** — if no command scores above 0.0, returns the
           ``/nlq`` (natural-language query) command as a safe fallback.

        Setpoints are extracted heuristically: quoted strings, numbers,
        ``key=value`` pairs, and ``--flag value`` patterns in *description* are
        parsed into the ``setpoints`` dict.

        Args:
            description: Natural-language description of the desired action, e.g.
                         ``"run the sales ETL pipeline with 3 replicas"``.
            context: Optional dict with extra hints, e.g.
                     ``{"category": "data", "module": "data_pipeline_orchestrator"}``.
            top_n: How many alternative commands to include in the result.

        Returns:
            A :class:`GeneratedCommand` or ``None`` if the Librarian has no
            commands loaded yet (call :meth:`load_command_registry` first).
        """
        if not self.module_functions:
            logger.warning("generate_command: no commands loaded — call load_command_registry first")
            return None

        description_lower = description.lower().strip()
        desc_words = set(re.findall(r"\b[a-z0-9]+\b", description_lower))
        ctx = context or {}

        # ---- collect all command candidates from module_functions ----
        candidates: List[Dict[str, Any]] = []
        for module_name, funcs in self.module_functions.items():
            for slash_cmd, func_info in funcs.items():
                if not isinstance(func_info, dict):
                    continue
                # Build a searchable text blob for this command
                blob_parts = [
                    func_info.get("description", ""),
                    slash_cmd,
                    func_info.get("chat_command", ""),
                    func_info.get("usage", ""),
                ]
                blob_parts += func_info.get("nl_aliases", [])
                blob_parts += func_info.get("parameters", [])
                blob = " ".join(str(p) for p in blob_parts).lower()
                blob_words = set(re.findall(r"\b[a-z0-9]+\b", blob))

                # Score: Jaccard-style overlap weighted by description length
                overlap = desc_words & blob_words
                if not desc_words or not blob_words:
                    score = 0.0
                else:
                    score = len(overlap) / (len(desc_words) + len(blob_words) - len(overlap))

                # Boost when caller supplies a category or module hint
                if ctx.get("category") and ctx["category"] == func_info.get("category", ""):
                    score = min(1.0, score + 0.2)
                if ctx.get("module") and ctx["module"] == module_name:
                    score = min(1.0, score + 0.3)

                candidates.append({
                    "slash_command": slash_cmd,
                    "chat_command": func_info.get("chat_command", f"!murphy {slash_cmd.lstrip('/')}"),
                    "module_name": module_name,
                    "category": func_info.get("category", "system"),
                    "description": func_info.get("description", ""),
                    "usage": func_info.get("usage", slash_cmd),
                    "parameters": func_info.get("parameters", []),
                    "score": score,
                    "overlap_words": sorted(overlap),
                })

        if not candidates:
            return None

        # Sort by descending score
        candidates.sort(key=lambda c: c["score"], reverse=True)

        best = candidates[0]
        alternatives = [
            {"command": c["slash_command"], "description": c["description"], "score": round(c["score"], 4)}
            for c in candidates[1:top_n]
        ]

        # Fallback: if best score is 0.0, use /nlq with the raw description
        if best["score"] == 0.0:
            nlq_cmd = self.module_functions.get("natural_language_query", {}).get("/nlq")
            fallback_slash = "/nlq"
            fallback_chat = "!murphy nlq"
            if nlq_cmd and isinstance(nlq_cmd, dict):
                fallback_chat = nlq_cmd.get("chat_command", fallback_chat)
            return GeneratedCommand(
                command=f"{fallback_slash} {description}",
                chat_command=f"{fallback_chat} {description}",
                module_name="natural_language_query",
                category="terminal",
                description="Natural language query (fallback — no direct command match found)",
                setpoints=self._extract_setpoints(description),
                confidence=0.1,
                explanation="No command scored above 0.0; falling back to natural-language query.",
                alternatives=alternatives,
            )

        # ---- extract setpoints from description ----
        setpoints = self._extract_setpoints(description)

        # Inject positional subcommand from description if available
        param_names = best.get("parameters", [])
        if param_names and not setpoints:
            # Simple positional extraction: first non-command word as first param
            stop_words = set(re.findall(r"\b[a-z0-9]+\b", best["slash_command"].lower()))
            positional = [w for w in re.findall(r"\b\w+\b", description) if w.lower() not in stop_words]
            if positional and param_names:
                setpoints[param_names[0]] = positional[0]

        explanation = (
            f"Matched '{best['slash_command']}' (module: {best['module_name']}) "
            f"with score {best['score']:.3f} via keyword overlap: {best['overlap_words'][:6]}."
        )
        if ctx.get("category") or ctx.get("module"):
            explanation += " Context hints boosted the score."

        # Build the final command string with any setpoints
        cmd_str = best["slash_command"]
        for param, val in setpoints.items():
            cmd_str += f" --{param} {val}"

        return GeneratedCommand(
            command=cmd_str,
            chat_command=best["chat_command"],
            module_name=best["module_name"],
            category=best["category"],
            description=best["description"],
            setpoints=setpoints,
            confidence=min(1.0, best["score"]),
            explanation=explanation,
            alternatives=alternatives,
        )

    @staticmethod
    def _extract_setpoints(description: str) -> Dict[str, Any]:
        """Heuristically extract parameter setpoints from *description*.

        Recognises:
        * ``--key value`` and ``--key=value`` flag patterns
        * ``key=value`` and ``key: value`` inline assignments
        * Quoted strings → stored under ``"value"``
        * Bare integers/floats following a noun → stored under the
          singularised unit name (e.g. ``"3 replicas"`` → ``{"replica": "3"}``)
        """
        setpoints: Dict[str, Any] = {}

        # --key value  or  --key=value
        for m in re.finditer(r"--(\w+)[=\s]+([^\s,;]+)", description):
            setpoints[m.group(1)] = m.group(2)

        # key=value
        for m in re.finditer(r"\b(\w+)=([^\s,;]+)", description):
            setpoints[m.group(1)] = m.group(2)

        # "quoted strings"
        quoted = re.findall(r'"([^"]+)"', description)
        if quoted and "value" not in setpoints:
            setpoints["value"] = quoted[0]

        # Bare integers/floats (e.g. "3 replicas", "5000 dollars")
        for m in re.finditer(r"\b(\d+(?:\.\d+)?)\s+(\w+)", description):
            unit = m.group(2).rstrip("s")  # singularise
            setpoints.setdefault(unit, m.group(1))

        return setpoints


